import React, { useState, useEffect } from "react";
import { getCategories, createCategory, deleteCategory } from "../services/CategoryService";
import styles from "../styles/CategoryManager.module.css";

const CategoryManager = ({ onCategoriesChange }) => {
  const [categories, setCategories] = useState([]);
  const [newTitle, setNewTitle] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const data = await getCategories();
      setCategories(data);
      if(onCategoriesChange) onCategoriesChange(data);
    } catch (err) {
      setError("Error al cargar categorías.");
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    if (!newTitle.trim()) return;

    try {
      const cat = await createCategory({ title: newTitle });
      const updated = [...categories, cat];
      setCategories(updated);
      setNewTitle("");
      setError("");
      if(onCategoriesChange) onCategoriesChange(updated);
    } catch (err) {
      setError("Error al crear categoría. Asegúrate de tener permisos.");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("¿Seguro que quieres borrar esta categoría?")) return;
    try {
      await deleteCategory(id);
      const updated = categories.filter((c) => c.id !== id);
      setCategories(updated);
      setError("");
      if(onCategoriesChange) onCategoriesChange(updated);
    } catch (err) {
      setError("Error al borrar categoría. Podría estar en uso por alguna tarea.");
    }
  };

  return (
    <div className={styles.container}>
      <h3 className={styles.title}>🛠️ Panel de Administración</h3>
      <p className={styles.subtitle}>Gestión de Listas (Solo GESTOR/ADMIN)</p>

      {error && <div className={styles.error}>⚠️ {error}</div>}

      <form onSubmit={handleAdd} className={styles.form}>
        <input 
          type="text" 
          placeholder="Nueva lista..." 
          value={newTitle} 
          onChange={(e) => setNewTitle(e.target.value)} 
          className={styles.input}
        />
        <button type="submit" className={styles.button}>
          Crear
        </button>
      </form>

      <ul className={styles.list}>
        {categories.length === 0 && <li className={styles.empty}>No hay listas. Crea una.</li>}
        {categories.map((cat) => (
          <li key={cat.id} className={styles.listItem}>
            <span className={styles.catTitle}>{cat.title}</span>
            <button onClick={() => handleDelete(cat.id)} className={styles.deleteBtn}>
              Borrar
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default CategoryManager;
